import { useTranslation } from "react-i18next";
import {
  Sheet,
  SheetContent,
  SheetTitle,
} from "@/components/ui/sheet";
import * as VisuallyHidden from "@radix-ui/react-visually-hidden";
import EditRecipeWizard from "./recipe/EditRecipeWizard";
import { CommunityPost } from "@/hooks/useCommunityPosts";

interface EditRecipeDialogProps {
  post: CommunityPost;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

const EditRecipeDialog = ({ post, open, onOpenChange }: EditRecipeDialogProps) => {
  const { t } = useTranslation();

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent
        side="bottom"
        className="h-full flex flex-col p-0 rounded-none border-0 [&>button]:hidden"
      >
        <VisuallyHidden.Root>
          <SheetTitle>{t("recipe.editTitle", "编辑食谱")}</SheetTitle>
        </VisuallyHidden.Root>
        <EditRecipeWizard
          post={post as any}
          onClose={() => onOpenChange(false)}
          onSuccess={() => onOpenChange(false)}
        />
      </SheetContent>
    </Sheet>
  );
};

export default EditRecipeDialog;
